const raw = items[0].json;
let jobs = [];
try {
  const decoded = Buffer.from(raw.content, 'base64').toString('utf8');
  jobs = JSON.parse(decoded);
  if (!Array.isArray(jobs)) jobs = [];
} catch (e) {
  jobs = [];
}

jobs.sort((a, b) => (b.relevance_score || 0) - (a.relevance_score || 0));
const top5 = jobs.slice(0, 5);

const today = new Date().toLocaleDateString('en-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', timeZone: 'Asia/Kolkata' });

const scoreBar = (score) => {
  const filled = Math.round(score / 10);
  return '\u2588'.repeat(filled) + '\u2591'.repeat(10 - filled) + ` ${score}/100`;
};

const n8nBaseUrl = $env.N8N_WEBHOOK_URL || 'http://localhost:5678';

const jobCards = top5.map((j, i) => `
      <div style="background:#1e293b;border-radius:12px;padding:24px;margin-bottom:20px;border-left:4px solid ${i === 0 ? '#6366f1' : i === 1 ? '#8b5cf6' : i === 2 ? '#a78bfa' : '#cbd5e1'};">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:12px;">
          <div>
            <span style="background:#6366f1;color:#fff;font-size:11px;font-weight:700;padding:3px 10px;border-radius:20px;letter-spacing:1px;">#${i + 1} PICK</span>
            <h2 style="color:#f1f5f9;font-size:20px;font-weight:700;margin:8px 0 4px;">${j.title}</h2>
            <p style="color:#94a3b8;font-size:14px;margin:0;">&#127970; ${j.company} &nbsp;|&nbsp; &#128205; ${j.location} &nbsp;|&nbsp; &#128279; ${j.source}</p>
          </div>
          <div style="text-align:right;flex-shrink:0;margin-left:16px;">
            <div style="background:linear-gradient(135deg,#6366f1,#8b5cf6);border-radius:8px;padding:10px 16px;">
              <div style="color:#fff;font-size:28px;font-weight:800;">${j.relevance_score || 0}</div>
              <div style="color:#c7d2fe;font-size:10px;letter-spacing:1px;">SCORE</div>
            </div>
          </div>
        </div>
        <div style="background:#0f172a;border-radius:8px;padding:12px;margin:12px 0;font-family:monospace;color:#a5f3fc;font-size:12px;">
          ${scoreBar(j.relevance_score || 0)}
        </div>
        ${j.score_reason ? `<p style="color:#94a3b8;font-size:13px;font-style:italic;margin:8px 0;">${j.score_reason}</p>` : ''}
        <div style="display:flex;align-items:center;justify-content:space-between;margin-top:16px;">
          <a href="${j.url}" style="background:linear-gradient(135deg,#6366f1,#8b5cf6);color:#fff;text-decoration:none;padding:10px 20px;border-radius:8px;font-size:13px;font-weight:600;">Apply Now &#8594;</a>
          <a href="${n8nBaseUrl}/webhook/approve-job?jobId=${j.job_id}" style="background:linear-gradient(135deg,#22c55e,#16a34a);color:#fff;text-decoration:none;padding:10px 20px;border-radius:8px;font-size:13px;font-weight:600;">&#9989; APPROVE - Get Resume</a>
        </div>
      </div>`).join('');

const html = `<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="margin:0;padding:0;background:#0f172a;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#0f172a;min-height:100vh;">
    <tr><td align="center" style="padding:40px 20px;">
      <table width="640" cellpadding="0" cellspacing="0" style="max-width:640px;width:100%;">
        <tr><td style="background:linear-gradient(135deg,#1e1b4b 0%,#312e81 50%,#1e1b4b 100%);border-radius:16px 16px 0 0;padding:40px 32px;text-align:center;">
          <h1 style="color:#e0e7ff;font-size:32px;font-weight:800;margin:0 0 8px;">&#129302; AI Job Intelligence</h1>
          <p style="color:#a5b4fc;font-size:16px;margin:0;">Your Daily Digest - ${today}</p>
          <div style="background:rgba(255,255,255,0.1);border-radius:8px;padding:12px 24px;margin-top:20px;display:inline-block;">
            <span style="color:#c7d2fe;font-size:14px;">&#9889; ${top5.length} top opportunities scored for you</span>
          </div>
        </td></tr>
        <tr><td style="background:#0f172a;padding:32px;border-radius:0 0 16px 16px;">
          ${jobCards}
          <div style="text-align:center;margin-top:32px;padding-top:24px;border-top:1px solid #1e293b;">
            <p style="color:#475569;font-size:12px;">Generated by your n8n AI Job Intelligence System</p>
            <p style="color:#22c55e;font-size:13px;font-weight:600;">Click the green APPROVE button on any job to instantly get a tailored resume!</p>
          </div>
        </td></tr>
      </table>
    </td></tr>
  </table>
</body></html>`;

return [{ json: { html_body: html, subject: `AI Job Digest - ${today} - ${top5.length} jobs scored` } }];

const jobId = items[0].json.query.jobId || items[0].json.body.jobId || '';
if (!jobId || !jobId.startsWith('j_')) {
  return [{ json: { _no_approve: true, error: 'Invalid or missing jobId' } }];
}
return [{ json: { job_id: jobId } }];

const allItems = items;

let resumeItem = null;
let atsItem = null;

for (const i of allItems) {
  if (i.json.name && String(i.json.name).endsWith('_resume.md')) {
    resumeItem = i.json;
  } else if (i.json.name && String(i.json.name).endsWith('_ats_report.json')) {
    atsItem = i.json;
  }
}

if (!resumeItem && !atsItem) {
  resumeItem = allItems[0] ? allItems[0].json : null;
  atsItem = allItems[1] ? allItems[1].json : null;
}

let resumeText = '';
let atsData = {};
let jobId = 'unknown';

if (resumeItem && resumeItem.content) {
  resumeText = Buffer.from(resumeItem.content, 'base64').toString('utf8');
  jobId = (resumeItem.name || '').replace('_resume.md', '');
}

if (atsItem && atsItem.content) {
  try {
    atsData = JSON.parse(Buffer.from(atsItem.content, 'base64').toString('utf8'));
  } catch (e) {
    atsData = {};
  }
}

const resume_b64 = Buffer.from(resumeText).toString('base64');
const atsJson = JSON.stringify(atsData, null, 2);

const scoreColor = (s) => s >= 80 ? '#22c55e' : s >= 60 ? '#eab308' : '#ef4444';
const score = atsData.overall_score || 0;

const html = `<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;background:#0f172a;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#0f172a;">
    <tr><td align="center" style="padding:40px 20px;">
      <table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;">
        <tr><td style="background:linear-gradient(135deg,#064e3b,#065f46);border-radius:16px 16px 0 0;padding:32px;text-align:center;">
          <h1 style="color:#ecfdf5;font-size:28px;font-weight:800;margin:0 0 8px;">Resume Ready!</h1>
          <p style="color:#a7f3d0;font-size:14px;margin:0;">Your tailored resume for <strong>${jobId}</strong></p>
        </td></tr>
        <tr><td style="background:#1e293b;padding:32px;border-radius:0 0 16px 16px;">
          <div style="background:#0f172a;border-radius:12px;padding:24px;margin-bottom:20px;text-align:center;">
            <div style="font-size:48px;font-weight:800;color:${scoreColor(score)};">${score}</div>
            <div style="color:#94a3b8;font-size:14px;">ATS Score / 100</div>
          </div>
          ${atsData.matched_keywords ? `<div style="background:#0f172a;border-radius:8px;padding:16px;margin-bottom:16px;"><p style="color:#a5f3fc;font-size:12px;font-weight:700;margin:0 0 8px;">MATCHED KEYWORDS</p><p style="color:#cbd5e1;font-size:12px;margin:0;">${atsData.matched_keywords.join(', ')}</p></div>` : ''}
          ${atsData.missing_keywords ? `<div style="background:#0f172a;border-radius:8px;padding:16px;margin-bottom:16px;"><p style="color:#fca5a5;font-size:12px;font-weight:700;margin:0 0 8px;">MISSING KEYWORDS</p><p style="color:#cbd5e1;font-size:12px;margin:0;">${atsData.missing_keywords.join(', ')}</p></div>` : ''}
          <p style="color:#94a3b8;font-size:13px;margin:16px 0 0;">Your tailored resume is attached to this email.</p>
        </td></tr>
      </table>
    </td></tr>
  </table>
</body></html>`;

return [{
  json: {
    job_id: jobId,
    html_body: html,
    subject: `Your Resume for ${jobId} - ATS Score: ${score}/100`,
    ats_score: score
  },
  binary: {
    resume: {
      data: resume_b64,
      mimeType: 'text/markdown',
      fileName: `${jobId}_resume.md`
    }
  }
}];
